from __future__ import annotations
from typing import TypeVar, Generic

T = TypeVar('T')       # unconstrained: any type
N = TypeVar('N', int, float)  # constrained: only int or float


# --- Generic Stack[T] ---
class Stack(Generic[T]):
    def __init__(self) -> None:
        self._items: list[T] = []

    def push(self, item: T) -> None:
        self._items.append(item)

    def pop(self) -> T:
        if not self._items:
            raise IndexError('pop from empty stack')
        return self._items.pop()

    def peek(self) -> T | None:
        return self._items[-1] if self._items else None

    def __len__(self) -> int:
        return len(self._items)

    def __repr__(self) -> str:
        return f'Stack({self._items!r})'


# Type-safe usage — T is inferred from first push
int_stack: Stack[int] = Stack()
int_stack.push(1)
int_stack.push(2)
value: int = int_stack.pop()   # type: int
print(value)                    # 2

str_stack: Stack[str] = Stack()
str_stack.push('hello')
str_stack.push('world')
word: str = str_stack.pop()    # type: str
print(word)                     # world

# int_stack.push('oops')  # mypy/pyright error: str not assignable to int


# --- Generic Result[T, E]: success-or-error pattern ---
E = TypeVar('E', bound=Exception)

class Ok(Generic[T]):
    def __init__(self, value: T) -> None:
        self.value = value

    def is_ok(self) -> bool:
        return True


class Err(Generic[E]):
    def __init__(self, error: E) -> None:
        self.error = error

    def is_ok(self) -> bool:
        return False


Result = Ok[T] | Err[E]


def safe_divide(a: float, b: float) -> Ok[float] | Err[ZeroDivisionError]:
    if b == 0:
        return Err(ZeroDivisionError('Division by zero'))
    return Ok(a / b)


result = safe_divide(10.0, 2.0)
if result.is_ok():
    assert isinstance(result, Ok)
    print(result.value)   # 5.0

from __future__ import annotations
from typing import Protocol, runtime_checkable


# --- Protocol: structural subtyping ---
# Any class with these methods satisfies Drawable
# — no explicit inheritance needed.
class Drawable(Protocol):
    def draw(self) -> None: ...
    def get_bounds(self) -> tuple[int, int, int, int]: ...
      # returns (x, y, width, height)


class Resizable(Protocol):
    def resize(self, factor: float) -> None: ...


# Combine protocols with intersection (Python 3.12+)
# For older Python, create a combined protocol:
class DrawableResizable(Drawable, Resizable, Protocol):
    pass


# --- Implementations: no explicit inheritance ---
class Circle:
    def __init__(self, x: int, y: int, radius: int) -> None:
        self.x, self.y, self.radius = x, y, radius

    def draw(self) -> None:
        print(f'Drawing circle at ({self.x},{self.y}) r={self.radius}')

    def get_bounds(self) -> tuple[int, int, int, int]:
        d = self.radius * 2
        return (self.x - self.radius, self.y - self.radius, d, d)

    def resize(self, factor: float) -> None:
        self.radius = int(self.radius * factor)


class Rectangle:
    def __init__(self, x: int, y: int, w: int, h: int) -> None:
        self.x, self.y, self.w, self.h = x, y, w, h

    def draw(self) -> None:
        print(f'Drawing rect at ({self.x},{self.y}) {self.w}x{self.h}')

    def get_bounds(self) -> tuple[int, int, int, int]:
        return (self.x, self.y, self.w, self.h)

    def resize(self, factor: float) -> None:
        self.w = int(self.w * factor)
        self.h = int(self.h * factor)


# --- Functions that accept the protocol ---
def render_all(shapes: list[Drawable]) -> None:
    for shape in shapes:
        shape.draw()


def resize_all(shapes: list[DrawableResizable], factor: float) -> None:
    for shape in shapes:
        shape.resize(factor)


shapes: list[Drawable] = [Circle(0, 0, 10), Rectangle(5, 5, 20, 10)]
render_all(shapes)   # works — both classes satisfy Drawable
